// Extract and normalize product data for AI prompt
const product = $input.first().json.product;

const title = product.title || '';
const productType = product.product_type || 'Crystal';
const vendor = product.vendor || 'Wax | Wane';
const tags = (product.tags || '').split(',').map(t => t.trim()).filter(Boolean);
const variants = product.variants || [];
const images = product.images || [];
const existingDesc = product.body_html || '';

// Build variant summary
const variantSummary = variants.map(v => {
  const opts = [v.option1, v.option2, v.option3].filter(Boolean).join(' / ');
  return `${opts} — SKU: ${v.sku || 'N/A'} — $${v.price}`;
}).join('\n');

// Detect crystal type from title
const titleLower = title.toLowerCase();
let crystalType = 'crystal';
if (titleLower.includes('fluorite')) crystalType = 'fluorite';
else if (titleLower.includes('quartz')) crystalType = 'quartz';
else if (titleLower.includes('amethyst')) crystalType = 'amethyst';
else if (titleLower.includes('moonstone')) crystalType = 'moonstone';
else if (titleLower.includes('lapis')) crystalType = 'lapis lazuli';
else if (titleLower.includes('shungite')) crystalType = 'shungite';
else if (titleLower.includes('jasper')) crystalType = 'jasper';
else if (titleLower.includes('hematite')) crystalType = 'hematite';
else if (titleLower.includes('terahertz')) crystalType = 'terahertz';
else if (titleLower.includes('citrine')) crystalType = 'citrine';
else if (titleLower.includes('jade')) crystalType = 'jade';
else if (titleLower.includes('tiger')) crystalType = "tiger's eye";
else if (titleLower.includes('bracelet')) crystalType = 'gemstone bracelet';

// Detect product form
let productForm = 'tower';
if (titleLower.includes('sphere') || titleLower.includes('ball')) productForm = 'sphere';
else if (titleLower.includes('bracelet')) productForm = 'bracelet';
else if (titleLower.includes('keychain')) productForm = 'keychain';
else if (titleLower.includes('pyramid')) productForm = 'pyramid';
else if (titleLower.includes('cube')) productForm = 'cube';
else if (titleLower.includes('cup') || titleLower.includes('mug')) productForm = 'cup';
else if (titleLower.includes('palm')) productForm = 'palm stone';
else if (titleLower.includes('flame')) productForm = 'flame sculpture';

return [{
  json: {
    product_id: product.id,
    title,
    product_type: productType,
    vendor,
    tags,
    variant_summary: variantSummary,
    variant_count: variants.length,
    image_count: images.length,
    existing_description: existingDesc.replace(/<[^>]*>/g, '').substring(0, 500),
    crystal_type: crystalType,
    product_form: productForm,
    handle: product.handle,
    shopify_url: `https://waxandwane.store/products/${product.handle}`
  }
}];

