// Parse the AI response JSON
const aiResponse = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';

let content;
try {
  // Strip any markdown code fences if present
  const cleaned = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  content = JSON.parse(cleaned);
} catch(e) {
  // Fallback: return error state
  return [{ json: { parse_error: true, raw: aiResponse.substring(0, 500) } }];
}

// Merge with product context from previous node
const productData = $('🔍 Extract & Normalize Product Data').first().json;

return [{
  json: {
    ...productData,
    ...content,
    generated_at: new Date().toISOString()
  }
}];

// Build Veeqo channel push payload
// Veeqo channel IDs: Walmart=1009103, TikTok=1044457, Amazon=1049861, Etsy=1049903
